function scoreAnswers(answers) {
  const counts = { A: 0, B: 0, C: 0, D: 0 };
  answers.forEach((v) => { if (counts[v] !== undefined) counts[v]++; });
  const max = Math.max(...Object.values(counts));
  for (const k of ["D", "C", "B", "A"]) {
    if (counts[k] === max) return k;
  }
  return "A";
}

// ─── APP ─────────────────────────────────────────────────────────────────────

export default function BloomStartup() {
  const [screen, setScreen]           = useState("landing");
  const [qIndex, setQIndex]           = useState(0);
  const [answers, setAnswers]         = useState([]);
  const [fading, setFading]           = useState(false);
  const [selected, setSelected]       = useState(null);
  const [pendingResult, setPending]   = useState(null);
  const [result, setResult]           = useState(null);
  const [heroIn, setHeroIn]           = useState(false);
  const [submitErr, setSubmitErr]     = useState("");
  const topRef = useRef(null);

  useEffect(() => { setTimeout(() => setHeroIn(true), 90); }, []);
  useEffect(() => { topRef.current?.scrollIntoView({ behavior: "smooth" }); }, [screen]);

  const finishQuiz = (final) => {
    const key = scoreAnswers(final);
    setPending(RESULTS[key]);
    setScreen("capture");
  };

  const handleAnswer = (val) => {
    if (fading) return;
    setSelected(val);
    setTimeout(() => {
      const next = [...answers, val];
      setAnswers(next);
      setFading(true);
      setTimeout(() => {
        setSelected(null);
        if (qIndex < QUESTIONS.length - 1) setQIndex(qIndex + 1);
        else finishQuiz(next);
        setFading(false);
      }, 260);
    }, 150);
  };

  // Submit name + email to Kit with the correct stage tag, then reveal results
  const handleKitSubmit = async ({ firstName, email }) => {
    setScreen("submitting");
    setSubmitErr("");

    // Find which answer key (A/B/C/D) produced the pending result
    const resultKey = Object.keys(RESULTS).find(
      (k) => RESULTS[k].stage === pendingResult.stage
    ) || "A";
    const tagId = KIT_TAGS[resultKey];

    try {
      const body = new FormData();
      body.append("email_address", email);
      body.append("first_name", firstName);
      // Apply the stage tag directly to their Kit subscriber record
      body.append("tags[]", tagId);
      // no-cors — Kit returns an opaque response; treat any response as success
      await fetch(KIT_FORM_URL, { method: "POST", body, mode: "no-cors" });
    } catch (_) {}

    // Always proceed to results — never block the user on a network error
    setResult(pendingResult);
    setScreen("results");
  };

  const reset = () => {
    setScreen("landing"); setQIndex(0); setAnswers([]);
    setPending(null); setResult(null); setSubmitErr("");
  };

  const progress = ((qIndex + 1) / QUESTIONS.length) * 100;

  return (
    <div ref={topRef} style={S.root}>
      <GlobalCSS />
      <div style={S.grain} />
      <div style={S.orb1} />
      <div style={S.orb2} />
      <div style={S.orb3} />

      {screen === "landing"    && <Landing onStart={() => setScreen("quiz")} heroIn={heroIn} />}
      {screen === "quiz"       && (
        <Quiz
          q={QUESTIONS[qIndex]} qIndex={qIndex} total={QUESTIONS.length}
          progress={progress} fading={fading} selected={selected}
          onAnswer={handleAnswer}
          onBack={() => {
            if (qIndex === 0) setScreen("landing");
            else { setQIndex(qIndex - 1); setAnswers(answers.slice(0, -1)); }
          }}
        />
      )}
      {screen === "capture"    && (
        <KitCapture
          onSubmit={handleKitSubmit}
          onBack={() => { setScreen("quiz"); setQIndex(QUESTIONS.length - 1); setAnswers(answers.slice(0, -1)); }}
          error={submitErr}
        />
      )}
      {screen === "submitting" && <Submitting />}
      {screen === "results"    && result && <Results result={result} onReset={reset} />}
    </div>
  );
}

